"use client";

import {
  useCallback,
  useEffect,
  useRef,
  useState,
  useSyncExternalStore,
} from "react";

/** Master bus level — the drone sits well under full scale. */
const MASTER_LEVEL = 0.38;
/** Fade-in of the room tone (s). */
const ATTACK_S = 1.6;
/** Fade-out on stop (s) — nodes are torn down right after it lands. */
const RELEASE_S = 0.55;
/** The strings enter three seconds late, on purpose. */
const STRINGS_DELAY_S = 3;
/** Once they enter, the strings take this long to swell in (s). */
const STRINGS_SWELL_S = 2.8;

type Engine = {
  ctx: AudioContext;
  master: GainNode;
  analyser: AnalyserNode;
  sources: OscillatorNode[];
  torn: boolean;
};

function getContextCtor(): typeof AudioContext | null {
  if (typeof window === "undefined") return null;
  const w = window as Window & { webkitAudioContext?: typeof AudioContext };
  return window.AudioContext ?? w.webkitAudioContext ?? null;
}

/**
 * Web Audio capability as a tiny external store: the server optimistically
 * says "supported", the client corrects it synchronously on hydration, and
 * a failed AudioContext construction can flip it later (hiding the player).
 * Capability is global, so the store is module-level on purpose.
 */
let audioBroken = false;
const supportListeners = new Set<() => void>();

function markAudioBroken() {
  if (audioBroken) return;
  audioBroken = true;
  for (const listener of supportListeners) listener();
}

function subscribeSupport(onChange: () => void): () => void {
  supportListeners.add(onChange);
  return () => {
    supportListeners.delete(onChange);
  };
}

function getSupportSnapshot(): boolean {
  return !audioBroken && getContextCtor() !== null;
}

function getSupportServerSnapshot(): boolean {
  return true;
}

/**
 * Cue 04 as a synth patch, built only on an explicit user gesture — never on
 * mount, never on scroll. The graph:
 *
 *   room:    sine 55 + sine 110.7 + tri 164.8 → lowpass 260 → gain
 *   strings: saw 220 + saw 220.9 + saw 329.6 → lowpass 880 (LFO-breathed)
 *            → swell (LFO) → envelope (enters at t+3s)
 *   both → master (attack/release envelope) → analyser → destination
 *
 * `stop()` ramps the master to silence, then stops every oscillator,
 * disconnects the graph, and closes the AudioContext — nothing leaks, and a
 * closed context is also the teardown path on unmount and pagehide.
 */
export function useAudioEngine() {
  const supported = useSyncExternalStore(
    subscribeSupport,
    getSupportSnapshot,
    getSupportServerSnapshot,
  );
  const [playing, setPlaying] = useState(false);
  const engineRef = useRef<Engine | null>(null);
  const fadingRef = useRef<Engine | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const fadeTimerRef = useRef(0);

  const teardown = useCallback((engine: Engine) => {
    if (engine.torn) return;
    engine.torn = true;
    for (const src of engine.sources) {
      try {
        src.stop();
      } catch {
        /* already stopped or never started — fine */
      }
    }
    try {
      engine.master.disconnect();
      engine.analyser.disconnect();
    } catch {
      /* context already closing */
    }
    void engine.ctx.close().catch(() => undefined);
  }, []);

  const stop = useCallback(() => {
    const engine = engineRef.current;
    if (!engine) return;
    engineRef.current = null;
    analyserRef.current = null;
    setPlaying(false);

    // Ramp out, then dismantle: no clicks, no orphaned nodes.
    const now = engine.ctx.currentTime;
    const g = engine.master.gain;
    g.cancelScheduledValues(now);
    g.setValueAtTime(Math.max(g.value, 0.0001), now);
    g.exponentialRampToValueAtTime(0.0001, now + RELEASE_S);

    fadingRef.current = engine;
    window.clearTimeout(fadeTimerRef.current);
    fadeTimerRef.current = window.setTimeout(() => {
      teardown(engine);
      if (fadingRef.current === engine) fadingRef.current = null;
    }, RELEASE_S * 1000 + 80);
  }, [teardown]);

  const start = useCallback(() => {
    if (engineRef.current) return;
    const Ctor = getContextCtor();
    if (!Ctor) {
      markAudioBroken();
      return;
    }
    let ctx: AudioContext;
    try {
      ctx = new Ctor();
    } catch {
      markAudioBroken();
      return;
    }
    void ctx.resume().catch(() => undefined);

    const now = ctx.currentTime + 0.05;
    const sources: OscillatorNode[] = [];

    const master = ctx.createGain();
    master.gain.setValueAtTime(0.0001, now);
    master.gain.exponentialRampToValueAtTime(MASTER_LEVEL, now + ATTACK_S);

    const analyser = ctx.createAnalyser();
    analyser.fftSize = 2048;
    analyser.smoothingTimeConstant = 0.82;
    master.connect(analyser);
    analyser.connect(ctx.destination);

    const voice = (
      type: OscillatorType,
      freq: number,
      level: number,
      dest: AudioNode,
      at: number,
    ) => {
      const osc = ctx.createOscillator();
      osc.type = type;
      osc.frequency.value = freq;
      const g = ctx.createGain();
      g.gain.value = level;
      osc.connect(g);
      g.connect(dest);
      osc.start(at);
      sources.push(osc);
    };

    // -- the room: two dark sines and a distant fifth ----------------------
    const roomFilter = ctx.createBiquadFilter();
    roomFilter.type = "lowpass";
    roomFilter.frequency.value = 260;
    const roomGain = ctx.createGain();
    roomGain.gain.value = 0.62;
    roomFilter.connect(roomGain);
    roomGain.connect(master);

    voice("sine", 55, 1, roomFilter, now); // A1 — the floor of the room
    voice("sine", 110.7, 0.4, roomFilter, now); // an octave up, a hair sharp
    voice("triangle", 164.8, 0.15, roomFilter, now); // E3 — a distant fifth

    // -- the strings: detuned saws, filtered, three seconds late -----------
    const strFilter = ctx.createBiquadFilter();
    strFilter.type = "lowpass";
    strFilter.frequency.value = 880;
    strFilter.Q.value = 1.4;

    const swell = ctx.createGain();
    swell.gain.value = 1;

    const strEnv = ctx.createGain();
    const enter = now + STRINGS_DELAY_S;
    strEnv.gain.setValueAtTime(0.0001, now);
    strEnv.gain.setValueAtTime(0.0001, enter);
    strEnv.gain.linearRampToValueAtTime(0.17, enter + STRINGS_SWELL_S);

    strFilter.connect(swell);
    swell.connect(strEnv);
    strEnv.connect(master);

    voice("sawtooth", 220, 0.5, strFilter, enter); // A3
    voice("sawtooth", 220.9, 0.5, strFilter, enter); // A3, deliberately off
    voice("sawtooth", 329.6, 0.22, strFilter, enter); // E4 — the open fifth

    // -- slow weather: sub-0.2Hz LFOs so the drone never sits still --------
    const lfoTimbre = ctx.createOscillator();
    lfoTimbre.frequency.value = 0.07;
    const lfoTimbreDepth = ctx.createGain();
    lfoTimbreDepth.gain.value = 320;
    lfoTimbre.connect(lfoTimbreDepth);
    lfoTimbreDepth.connect(strFilter.frequency);
    lfoTimbre.start(now);
    sources.push(lfoTimbre);

    const lfoSwell = ctx.createOscillator();
    lfoSwell.frequency.value = 0.11;
    const lfoSwellDepth = ctx.createGain();
    lfoSwellDepth.gain.value = 0.24;
    lfoSwell.connect(lfoSwellDepth);
    lfoSwellDepth.connect(swell.gain);
    lfoSwell.start(now);
    sources.push(lfoSwell);

    const engine: Engine = { ctx, master, analyser, sources, torn: false };
    engineRef.current = engine;
    analyserRef.current = analyser;
    setPlaying(true);
  }, []);

  const toggle = useCallback(() => {
    if (engineRef.current) stop();
    else start();
  }, [start, stop]);

  // Hard teardown on unmount and pagehide — no fade, no leaks.
  useEffect(() => {
    const killAll = () => {
      window.clearTimeout(fadeTimerRef.current);
      if (fadingRef.current) {
        teardown(fadingRef.current);
        fadingRef.current = null;
      }
      if (engineRef.current) {
        teardown(engineRef.current);
        engineRef.current = null;
        analyserRef.current = null;
      }
    };
    const onPageHide = () => {
      killAll();
      setPlaying(false);
    };
    window.addEventListener("pagehide", onPageHide);
    return () => {
      window.removeEventListener("pagehide", onPageHide);
      killAll();
    };
  }, [teardown]);

  return { supported, playing, toggle, stop, analyserRef };
}

"use client";

import { useSyncExternalStore } from "react";

const QUERY = "(prefers-reduced-motion: reduce)";

function subscribe(onChange: () => void): () => void {
  const mql = window.matchMedia(QUERY);
  mql.addEventListener("change", onChange);
  return () => mql.removeEventListener("change", onChange);
}

function getSnapshot(): boolean {
  return window.matchMedia(QUERY).matches;
}

function getServerSnapshot(): boolean {
  return false;
}

/**
 * True when the OS asks for reduced motion.
 * SSR-safe: the server snapshot is `false`; on the client the real value is
 * read synchronously, and live changes to the setting re-render immediately.
 */
export function usePrefersReducedMotion(): boolean {
  return useSyncExternalStore(subscribe, getSnapshot, getServerSnapshot);
}

"use client";

import { useEffect, useRef } from "react";

/**
 * Reveals descendants marked with [data-reveal] as they enter the viewport,
 * by adding an `is-visible` class. The pre-reveal state (opacity/translate)
 * lives in styles.css and is gated behind the `.halflight-js` root class, so
 * the content is fully visible when JavaScript never runs.
 *
 * Elements that intersect in the same observer batch are staggered 70ms
 * apart via transition-delay, so a screenful never fades as one slab.
 */
export function useReveal<T extends HTMLElement>(disabled: boolean) {
  const rootRef = useRef<T | null>(null);

  useEffect(() => {
    const root = rootRef.current;
    if (!root) return;
    const targets = Array.from(
      root.querySelectorAll<HTMLElement>("[data-reveal]"),
    );

    if (disabled || !("IntersectionObserver" in window)) {
      for (const el of targets) el.classList.add("is-visible");
      return;
    }

    const io = new IntersectionObserver(
      (hits) => {
        let batch = 0;
        for (const hit of hits) {
          if (!hit.isIntersecting) continue;
          const el = hit.target as HTMLElement;
          el.style.transitionDelay = `${batch * 70}ms`;
          el.classList.add("is-visible");
          io.unobserve(el);
          batch += 1;
        }
      },
      { threshold: 0.15, rootMargin: "0px 0px -9% 0px" },
    );
    for (const el of targets) io.observe(el);
    return () => io.disconnect();
  }, [disabled]);

  return rootRef;
}

"use client";

import { useEffect, useRef, type RefObject } from "react";

/**
 * Drives `onProgress` with the 0→1 progress of a tall section scrolling
 * through the viewport: 0 while the section top is at or below the top of
 * the screen, 1 once its bottom has reached the bottom — the classic
 * "sticky stage inside an over-tall section" scrub window. Here it is the
 * projector: scroll position *is* position in the reel.
 *
 * rAF-throttled: scroll/resize only schedule a frame; the single
 * getBoundingClientRect read and all downstream writes happen together
 * inside that frame, so the scrub never interleaves layout reads and writes.
 *
 * When `enabled` is false (reduced motion, or the feature is off) nothing
 * is measured and nothing ever fires — the DOM stays in its static,
 * server-rendered state.
 */
export function useScrollProgress<T extends HTMLElement>(
  targetRef: RefObject<T | null>,
  onProgress: (p: number) => void,
  enabled: boolean,
): void {
  const callbackRef = useRef(onProgress);

  useEffect(() => {
    callbackRef.current = onProgress;
  });

  useEffect(() => {
    if (!enabled) return;
    const el = targetRef.current;
    if (!el) return;

    let raf = 0;
    let scheduled = false;

    const measure = () => {
      scheduled = false;
      const rect = el.getBoundingClientRect();
      const range = rect.height - window.innerHeight;
      if (range <= 0) {
        callbackRef.current(rect.top <= 0 ? 1 : 0);
        return;
      }
      const p = Math.min(1, Math.max(0, -rect.top / range));
      callbackRef.current(p);
    };

    const schedule = () => {
      if (scheduled) return;
      scheduled = true;
      raf = window.requestAnimationFrame(measure);
    };

    schedule(); // settle the initial position without waiting for a scroll
    window.addEventListener("scroll", schedule, { passive: true });
    window.addEventListener("resize", schedule);
    return () => {
      window.cancelAnimationFrame(raf);
      window.removeEventListener("scroll", schedule);
      window.removeEventListener("resize", schedule);
    };
  }, [enabled, targetRef]);
}

"use client";

import { useEffect, useRef } from "react";
import "./styles.css";
import { anton, notoSerifKr, spaceMono, spectral } from "./fonts";
import TitleCard from "./components/TitleCard";
import Reel from "./components/Reel";
import ScorePlayer from "./components/ScorePlayer";
import CueSheet from "./components/CueSheet";
import CreditsFooter from "./components/CreditsFooter";
import { usePrefersReducedMotion } from "./hooks/usePrefersReducedMotion";
import { useReveal } from "./hooks/useReveal";

/**
 * HALFLIGHT — original scores for imaginary films.
 * A composer writes music for films that were never shot; this page is the
 * studio's screening room. Every scroll section is a reel: a letterboxed
 * title card, a procedurally drawn film sequence scrubbed by scroll (no
 * video file anywhere), a cue you press play to hear (Web Audio, synthesized
 * live), a screenplay-style cue sheet, and end credits for nobody.
 *
 * `.halflight-js` is added on mount so every scroll/scrub/reveal style is
 * JS-gated — with JavaScript disabled the full page is simply readable.
 */
export default function HalflightPage() {
  const rootRef = useRef<HTMLDivElement | null>(null);
  const reduced = usePrefersReducedMotion();
  const revealRef = useReveal<HTMLElement>(reduced);

  useEffect(() => {
    // Imperative on purpose: the class is a signal to CSS that JS is alive,
    // not React state — and className never changes, so it sticks.
    rootRef.current?.classList.add("halflight-js");
    window.parent?.postMessage(
      { type: "oneshot:ready", slug: "halflight" },
      "*",
    );
  }, []);

  return (
    <div
      id="halflight-top"
      ref={rootRef}
      className={`${anton.variable} ${spectral.variable} ${spaceMono.variable} ${notoSerifKr.variable} halflight-root`}
    >
      <main className="halflight-picture" ref={revealRef}>
        <TitleCard />
        <Reel />
        <ScorePlayer />
        <CueSheet />
        <CreditsFooter />
      </main>
    </div>
  );
}

/* ==========================================================================
   HALFLIGHT — original scores for imaginary films
   cinematic-dark · grayscale + one signal red · letterboxed everything
   Scoped by convention to .halflight-root; classes prefixed halflight-.
   ========================================================================== */

.halflight-root {
  /* -- palette ---------------------------------------------------------- */
  --hl-black: #0b0b0d; /* the screen with the lamp off */
  --hl-abyss: #000000; /* letterbox bars, the frame surround */
  --hl-bone: #e8e4da; /* primary text — 15.5:1 on black */
  --hl-bone-dim: rgba(232, 228, 218, 0.64); /* ≈ #989690 — 6.6:1, secondary */
  --hl-red: #d43425; /* signal red — 4.0:1: large type & non-text only */
  --hl-tungsten: #a08560; /* warm metadata — 5.6:1 */
  --hl-line: rgba(232, 228, 218, 0.14); /* hairlines, decorative */

  /* -- type -------------------------------------------------------------- */
  --hl-font-display: var(--font-anton), "Anton", "Arial Narrow", sans-serif;
  /* Hangul falls through the Latin faces into Noto Serif KR without markup */
  --hl-font-body: var(--font-spectral), var(--font-noto-serif-kr), Georgia,
    serif;
  --hl-font-mono: var(--font-space-mono), var(--font-noto-serif-kr),
    "Courier New", monospace;
  --hl-font-ko: var(--font-noto-serif-kr), "Noto Serif KR", serif;

  /* -- motion ------------------------------------------------------------ */
  --hl-ease-out: cubic-bezier(0.16, 1, 0.3, 1); /* reveals: fast in, long tail */

  /* -- geometry ---------------------------------------------------------- */
  --hl-bar: clamp(44px, 9svh, 116px); /* hero letterbox bar height */
  --hl-frame-w: min(1100px, 92vw, 148svh); /* the 2.39:1 picture width */

  position: relative;
  min-height: 100vh;
  min-height: 100svh;
  background: var(--hl-black);
  color: var(--hl-bone);
  font-family: var(--hl-font-body);
  font-size: clamp(16px, 0.9vw + 11px, 19px);
  line-height: 1.65;
  overflow-x: hidden;
  overflow-x: clip;
}

/* Korean is first-class: its own serif, natural breaks, its own rhythm. */
.halflight-root :lang(ko) {
  font-family: var(--hl-font-ko);
  word-break: keep-all;
  letter-spacing: 0;
}

/* Signal-red selection, scoped to the entry root */
.halflight-root ::selection {
  background: var(--hl-red);
  color: var(--hl-bone);
  text-shadow: none;
}

/* Keyboard focus: the one red rectangle in the dark */
.halflight-root :focus-visible {
  outline: 2px solid var(--hl-red);
  outline-offset: 3px;
  border-radius: 1px;
}

.halflight-mono {
  font-family: var(--hl-font-mono);
}

.halflight-link {
  color: var(--hl-bone);
  text-decoration: underline;
  text-decoration-color: rgba(232, 228, 218, 0.3);
  text-underline-offset: 4px;
}

.halflight-link:hover {
  text-decoration-color: var(--hl-red);
}

/* Visually hidden, still read aloud */
.halflight-sr {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip-path: inset(50%);
  white-space: nowrap;
  border: 0;
}

/* ==========================================================================
   Shared section furniture
   ========================================================================== */

.halflight-sechead {
  margin: 0;
  font-family: var(--hl-font-display);
  font-weight: 400;
  font-size: clamp(1.9rem, 4.4vw, 3.2rem);
  line-height: 1.05;
  letter-spacing: 0.03em;
}

.halflight-sechead__ko {
  margin-left: 0.35em;
  font-size: 0.48em;
  font-weight: 600;
  color: var(--hl-bone-dim);
  letter-spacing: 0.04em;
  vertical-align: 0.22em;
}

.halflight-sechead__no {
  margin: 0 0 0.6rem;
  font-size: 0.76rem;
  letter-spacing: 0.24em;
  color: var(--hl-tungsten);
}

/* The reel-change cue mark — the page's single recurring red object */
.halflight-cuedot {
  position: absolute;
  top: calc(var(--hl-bar) + clamp(14px, 2.5svh, 26px));
  right: clamp(18px, 4vw, 44px);
  width: 13px;
  height: 13px;
  border-radius: 50%;
  background: var(--hl-red);
  box-shadow: 0 0 14px rgba(212, 52, 37, 0.5);
}

.halflight-js .halflight-hero > .halflight-cuedot {
  animation: hl-cue-blink 8.1s linear infinite;
}

/* ==========================================================================
   Reel 01 · Title card
   ========================================================================== */

.halflight-hero {
