.halflight-js [data-reveal] {
  opacity: 0;
  transform: translateY(18px);
  transition:
    opacity 600ms var(--hl-ease-out),
    transform 600ms var(--hl-ease-out);
  will-change: opacity, transform;
}

.halflight-js [data-reveal].is-visible {
  opacity: 1;
  transform: none;
}

/* ==========================================================================
   Keyframes — transform / opacity only
   ========================================================================== */

/* Each glyph of the title rises out of the letterbox */
@keyframes hl-ch-rise {
  from {
    opacity: 0;
    transform: translateY(0.35em);
  }
  to {
    opacity: 1;
    transform: none;
  }
}

/* Gate weave: the frame sits a hair loose in the projector gate.
   steps(1, end) holds each position, then jumps — film, not jelly. */
@keyframes hl-weave {
  0%,
  100% {
    transform: translate(0, 0);
  }
  9% {
    transform: translate(0.6px, -0.7px);
  }
  21% {
    transform: translate(-0.4px, 0.5px);
  }
  33% {
    transform: translate(0.3px, 0.9px);
  }
  46% {
    transform: translate(-0.7px, -0.3px);
  }
  58% {
    transform: translate(0.5px, 0.4px);
  }
  71% {
    transform: translate(-0.3px, -0.8px);
  }
  84% {
    transform: translate(0.7px, 0.2px);
  }
  93% {
    transform: translate(-0.5px, 0.6px);
  }
}

/* The projectionist's cue mark: two quick dips per cycle, mostly steady */
@keyframes hl-cue-blink {
  0%,
  90.5%,
  93.5%,
  100% {
    opacity: 1;
  }
  91.2% {
    opacity: 0.15;
  }
  92.1% {
    opacity: 1;
  }
  92.8% {
    opacity: 0.15;
  }
}

/* Grain jumps position discretely, like a new frame of stock */
@keyframes hl-grain {
  0%,
  100% {
    transform: translate(0, 0);
  }
  20% {
    transform: translate(-14px, 9px);
  }
  40% {
    transform: translate(11px, -16px);
  }
  60% {
    transform: translate(-7px, -11px);
  }
  80% {
    transform: translate(16px, 7px);
  }
}

/* The play button's red dot breathes while the cue sounds */
@keyframes hl-cue-pulse {
  0%,
  100% {
    opacity: 1;
  }
  50% {
    opacity: 0.35;
  }
}

/* ==========================================================================
   Reduced motion — a complete, calm, static page
   The reel becomes one still frame (drawn once by JS, or the CSS still);
   the title neither weaves nor rises; the credit roll is a plain list;
   grain and cue marks hold still. Audio stays user-triggerable.
   ========================================================================== */

@media (prefers-reduced-motion: reduce) {
  .halflight-js .halflight-title__ch,
  .halflight-js .halflight-title__weave,
  .halflight-js .halflight-hero > .halflight-cuedot,
  .halflight-js .halflight-grain,
  .halflight-js .halflight-play[aria-pressed="true"] .halflight-play__dot {
    animation: none;
  }

  .halflight-js [data-reveal] {
    opacity: 1;
    transform: none;
    transition: none;
  }

  .halflight-cuedot--reel {
    transition: none;
  }

  .halflight-js .halflight-reel {
    height: auto;
  }

  .halflight-js .halflight-reel__sticky {
    position: static;
    height: auto;
    padding: clamp(48px, 8svh, 96px) 0;
  }

  .halflight-js .halflight-credits {
    height: auto;
    padding: clamp(64px, 10vh, 128px) clamp(20px, 5vw, 64px);
  }

  .halflight-js .halflight-credits__sticky {
    position: static;
    height: auto;
    overflow: visible;
  }

  .halflight-js .halflight-credits__mask {
    height: auto;
    overflow: visible;
    -webkit-mask-image: none;
    mask-image: none;
  }

  .halflight-js .halflight-credits__roll {
    transform: none;
  }
}
